-- ملء محتوى عنقود "أحكام القرآن" (ahkam-quran) — خمسة تصنيفات فرعية
-- draft بالكامل: آيات أحكام الطهارة والصلاة والصيام والحج
-- (ayat-ahkam-ibadat)، آيات أحكام الأسرة والمواريث (ayat-ahkam-usrah)،
-- آيات أحكام المعاملات (ayat-ahkam-muamalat)، آيات أحكام القضاء
-- والجنايات والحدود (ayat-ahkam-qada-jinayat)، آيات الأخلاق والحقوق
-- والعلاقات (ayat-ahkam-huquq). كل تصنيف يحصل على درس واحد
-- (lessons + lesson_sections + lesson_citations)، بنفس أسلوب الدفعات
-- السابقة (تعريفي موجز: قسم body + قسم examples).
-- المصدر المعتمد لكل الدروس الخمسة: روائع البيان — تفسير آيات الأحكام
-- من القرآن الكريم لمحمد علي الصابوني (كتاب مؤلَّف أصلاً على هذا
-- التصنيف الفقهي الخماسي للعبادات/الأسرة/المعاملات/الحدود/الحقوق).
-- خمس آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: البقرة 183 (فرض الصيام)، النساء 11 (المواريث)،
-- البقرة 275 (إحلال البيع وتحريم الربا)، المائدة 38 (حد السرقة)،
-- النساء 36 (الحقوق العشرة). خمسة أحاديث استُشهد بها، تحقَّقت عبر
-- WebSearch قبل الإدراج (كلها متفق عليها): «من صام رمضان إيمانًا
-- واحتسابًا غفر له ما تقدم من ذنبه» عن أبي هريرة (البخاري 38، مسلم
-- 760)، «ألحقوا الفرائض بأهلها فما بقي فهو لأولى رجل ذكر» عن ابن عباس
-- (البخاري 6732، مسلم 1615)، «اجتنبوا السبع الموبقات» عن أبي هريرة
-- (البخاري 2615، مسلم 145)، حديث المرأة المخزومية «لو أن فاطمة بنت
-- محمد سرقت لقطعت يدها» عن عائشة (البخاري 3475، مسلم 1688)، «ما زال
-- جبريل يوصيني بالجار حتى ظننت أنه سيورثه» عن عائشة (البخاري 6014،
-- مسلم 2624).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) آيات أحكام الطهارة والصلاة والصيام والحج
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8df9b09b-22db-4bd5-b170-c4eb6dbb7b83' AND title='آيات أحكام الصيام: فريضة الصوم في سورة البقرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('آيات أحكام الصيام: فريضة الصوم في سورة البقرة', 'تعريف بآية فرض الصيام في سورة البقرة وبيان حكمتها في ضوء تفسير آيات الأحكام', '8df9b09b-22db-4bd5-b170-c4eb6dbb7b83', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'آيات أحكام العبادات في القرآن', 'آيات الأحكام المتعلقة بالعبادات (الطهارة والصلاة والصيام والحج) من أوسع أبواب فقه القرآن، جمعها الشيخ محمد علي الصابوني في كتابه "روائع البيان: تفسير آيات الأحكام من القرآن الكريم" مفسرًا ما تضمنته من أحكام فقهية مستنبطة من ظاهر النص مع بيان أقوال الفقهاء فيها. ومن أعظم آيات هذا الباب آية فرض الصيام في سورة البقرة، التي أسّست لركن من أركان الإسلام الخمسة وربطت الحكم بعلته مباشرة.', 1),
    (v_lesson, 'examples', 'آية فرض الصيام وحكمته', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ﴾ (البقرة: 183)، فرض الله بها الصيام على هذه الأمة كما فرضه على من قبلها من الأمم، وختمها بذكر العلة والحكمة منه وهي تحقيق التقوى. وقد بيّن النبي صلى الله عليه وسلم عظيم أجر من حقق هذه الحكمة، فعن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: «من صام رمضان إيمانًا واحتسابًا غفر له ما تقدم من ذنبه» (متفق عليه، رواه البخاري 38 ومسلم 760)، فربط المغفرة بتحقق الإيمان والاحتساب في الصيام، وهو عين التقوى المقصودة في الآية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روائع البيان: تفسير آيات الأحكام من القرآن الكريم — محمد علي الصابوني', 1);
  END IF;

  -- 2) آيات أحكام الأسرة والمواريث
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ec16ccf3-ec0f-43ba-9a6d-86510209ca68' AND title='آيات أحكام المواريث: قسمة التركة في سورة النساء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('آيات أحكام المواريث: قسمة التركة في سورة النساء', 'بيان آية المواريث الأولى في سورة النساء وقاعدة الفرائض النبوية المكمّلة لها', 'ec16ccf3-ec0f-43ba-9a6d-86510209ca68', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'آيات أحكام الأسرة والمواريث في القرآن', 'آيات أحكام الأسرة والمواريث من أدق أبواب آيات الأحكام وأكثرها تفصيلًا في تحديد الأنصبة رقميًا، وقد أفرد لها الشيخ محمد علي الصابوني في "روائع البيان: تفسير آيات الأحكام من القرآن الكريم" قسمًا مستقلًا لدقتها وكثرة ما تفرّع عنها من مسائل فقهية. وأعظم آيات هذا الباب آية المواريث الأولى في سورة النساء، التي فصّلت أنصبة الأولاد والأبوين من التركة.', 1),
    (v_lesson, 'examples', 'آية أنصبة الأولاد والأبوين وقاعدة الفرائض', 'قال تعالى: ﴿يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ ۖ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنثَيَيْنِ ۚ فَإِن كُنَّ نِسَاءً فَوْقَ اثْنَتَيْنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَ ۖ وَإِن كَانَتْ وَاحِدَةً فَلَهَا النِّصْفُ ۚ وَلِأَبَوَيْهِ لِكُلِّ وَاحِدٍ مِّنْهُمَا السُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُ وَلَدٌ﴾ (النساء: 11)، حددت نصيب الأولاد والأبوين من التركة تحديدًا رقميًا لا اجتهاد فيه. وقد جاءت السنة مكمّلة لهذا التفصيل فيما لم تنص عليه الآية صراحة، فعن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «ألحقوا الفرائض بأهلها، فما بقي فهو لأولى رجل ذكر» (متفق عليه، رواه البخاري 6732 ومسلم 1615)، فأسّس بذلك لقاعدة التعصيب المكمّلة لأصحاب الفروض المذكورين في الآية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روائع البيان: تفسير آيات الأحكام من القرآن الكريم — محمد علي الصابوني', 1);
  END IF;

  -- 3) آيات أحكام المعاملات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='067f79cb-55c2-4002-9922-4b82007c6c7a' AND title='آيات أحكام المعاملات: تحريم الربا وإحلال البيع في سورة البقرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('آيات أحكام المعاملات: تحريم الربا وإحلال البيع في سورة البقرة', 'بيان آيات الربا في سورة البقرة وموضع أكل الربا بين السبع الموبقات في السنة', '067f79cb-55c2-4002-9922-4b82007c6c7a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'آيات أحكام المعاملات المالية في القرآن', 'آيات أحكام المعاملات المالية من أوسع أبواب آيات الأحكام عددًا، وقد خصّها الشيخ محمد علي الصابوني بشرح مفصّل في "روائع البيان: تفسير آيات الأحكام من القرآن الكريم"، مبينًا فيها ضوابط البيوع والديون وتحريم الربا. ومن أعظم آياتها آيات الربا في سورة البقرة، وهي من أطول مواضع القرآن معالجةً لحكم مالي واحد، مما يدل على خطورته في نظر الشريعة.', 1),
    (v_lesson, 'examples', 'آية إحلال البيع وتحريم الربا', 'قال تعالى: ﴿الَّذِينَ يَأْكُلُونَ الرِّبَا لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ الَّذِي يَتَخَبَّطُهُ الشَّيْطَانُ مِنَ الْمَسِّ ۚ ذَٰلِكَ بِأَنَّهُمْ قَالُوا إِنَّمَا الْبَيْعُ مِثْلُ الرِّبَا وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، ردّت على من سوّى بين البيع والربا، وقرّرت الفارق الحكمي بينهما بإحلال أحدهما وتحريم الآخر. وقد جاءت السنة مؤكدة عظم شأن هذا التحريم، فعن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: «اجتنبوا السبع الموبقات» قالوا: يا رسول الله وما هن؟ قال: «الشرك بالله، والسحر، وقتل النفس التي حرم الله إلا بالحق، وأكل الربا، وأكل مال اليتيم، والتولي يوم الزحف، وقذف المحصنات المؤمنات الغافلات» (متفق عليه، رواه البخاري 2615 ومسلم 145)، فعدّ أكل الربا من السبع الموبقات المهلكات، مؤكدًا ما دلت عليه آية البقرة من شدة تحريمه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روائع البيان: تفسير آيات الأحكام من القرآن الكريم — محمد علي الصابوني', 1);
  END IF;

  -- 4) آيات أحكام القضاء والجنايات والحدود
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d8224652-c99b-4670-96e6-472aa31b9cff' AND title='آيات أحكام الحدود: حد السرقة في سورة المائدة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('آيات أحكام الحدود: حد السرقة في سورة المائدة', 'بيان آية حد السرقة في سورة المائدة ومبدأ المساواة أمام الحدود في حديث المرأة المخزومية', 'd8224652-c99b-4670-96e6-472aa31b9cff', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'آيات أحكام القضاء والجنايات والحدود في القرآن', 'آيات أحكام القضاء والجنايات والحدود من أشد آيات الأحكام صرامة في اللفظ لتحقيق الردع والزجر، تناولها الشيخ محمد علي الصابوني في "روائع البيان: تفسير آيات الأحكام من القرآن الكريم" مبينًا شروط إقامة كل حد وضوابطه الفقهية الدقيقة. ومن أظهر آيات هذا الباب آية حد السرقة في سورة المائدة.', 1),
    (v_lesson, 'examples', 'آية حد السرقة ومبدأ المساواة في إقامته', 'قال تعالى: ﴿وَالسَّارِقُ وَالسَّارِقَةُ فَاقْطَعُوا أَيْدِيَهُمَا جَزَاءً بِمَا كَسَبَا نَكَالًا مِّنَ اللَّهِ ۗ وَاللَّهُ عَزِيزٌ حَكِيمٌ﴾ (المائدة: 38)، فرضت قطع يد السارق والسارقة جزاءً وزجرًا لمن استوفى شروط هذا الحد الفقهية. وقد أكدت السنة أن هذا الحد لا يُستثنى منه أحد لجاه أو نسب، فعن عائشة رضي الله عنها أن قريشًا أهمّهم شأن المرأة المخزومية التي سرقت، فقال أسامة بن زيد للنبي صلى الله عليه وسلم، فتلوّن وجهه وقال: «أتشفع في حد من حدود الله؟» ثم قام فخطب فقال: «إنما أهلك الذين من قبلكم أنهم كانوا إذا سرق فيهم الشريف تركوه، وإذا سرق فيهم الضعيف أقاموا عليه الحد، وأيم الله لو أن فاطمة بنت محمد سرقت لقطعت يدها» (متفق عليه، رواه البخاري 3475 ومسلم 1688)، فقرّر مبدأ المساواة التام أمام الحدود دون تفريق بين شريف وضعيف.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روائع البيان: تفسير آيات الأحكام من القرآن الكريم — محمد علي الصابوني', 1);
  END IF;

  -- 5) آيات الأخلاق والحقوق والعلاقات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1cf6816f-1321-4dfc-a355-e6d5e952c8c0' AND title='آيات أحكام الحقوق: الوصية الجامعة بالوالدين والأقارب والجار في سورة النساء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('آيات أحكام الحقوق: الوصية الجامعة بالوالدين والأقارب والجار في سورة النساء', 'بيان آية الحقوق العشرة في سورة النساء وحديث وصية جبريل بحق الجار', '1cf6816f-1321-4dfc-a355-e6d5e952c8c0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'آيات الأخلاق والحقوق والعلاقات في القرآن', 'آيات الأخلاق والحقوق والعلاقات من آيات الأحكام الجامعة التي تحدد للمسلم دوائر من يستحقون حسن معاملته، تناولها الشيخ محمد علي الصابوني في "روائع البيان: تفسير آيات الأحكام من القرآن الكريم" ضمن آيات الحقوق والآداب. وأجمع آيات هذا الباب آية سورة النساء التي عدّدت عشرة أصناف مستحقين للإحسان بدءًا من الوالدين وانتهاءً بابن السبيل.', 1),
    (v_lesson, 'examples', 'آية الحقوق العشرة ووصية جبريل بالجار', 'قال تعالى: ﴿وَاعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَبِالْوَالِدَيْنِ إِحْسَانًا وَبِذِي الْقُرْبَىٰ وَالْيَتَامَىٰ وَالْمَسَاكِينِ وَالْجَارِ ذِي الْقُرْبَىٰ وَالْجَارِ الْجُنُبِ وَالصَّاحِبِ بِالْجَنبِ وَابْنِ السَّبِيلِ وَمَا مَلَكَتْ أَيْمَانُكُمْ ۗ إِنَّ اللَّهَ لَا يُحِبُّ مَن كَانَ مُخْتَالًا فَخُورًا﴾ (النساء: 36)، جمعت بين حق الله بالتوحيد وحقوق الخلق مرتبةً من الأقرب فالأقرب. وقد أفردت السنة حق الجار بتأكيد خاص لكثرة ما أوصى به الوحي فيه، فعن عائشة رضي الله عنها قالت: «ما زال جبريل يوصيني بالجار حتى ظننت أنه سيورثه» (متفق عليه، رواه البخاري 6014 ومسلم 2624)، وهو ما يفسر تكرار ذكر الجار مرتين في الآية بذي القربى وبعيد الدار.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روائع البيان: تفسير آيات الأحكام من القرآن الكريم — محمد علي الصابوني', 1);
  END IF;

  UPDATE categories SET status='published', updated_at=now()
  WHERE slug IN ('ayat-ahkam-ibadat','ayat-ahkam-usrah','ayat-ahkam-muamalat','ayat-ahkam-qada-jinayat','ayat-ahkam-huquq')
  AND status='draft';
END $$;
